            const clientSecret = await this.configurationService.getNewsApiSecret();
            if (!clientId || !clientSecret) {
                console.warn('Naver News API credentials not configured');
                return [];
            }
            // 네이버 API는 한 번에 최대 100개까지 요청 가능하지만, 
